=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Radar Corretor - Carrossel</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }

    body {
      width: 1200px;
      height: 1200px;
      background: #d9d9d9;
      display: flex;
      align-items: center;
      justify-content: center;
      font-family: 'Arial', sans-serif;
    }

    /* Container principal */
    .mosaic-container {
      width: 1200px;
      height: 1200px;
      background: #fff;
      border-radius: 30px;
      box-shadow: 0 20px 50px rgba(0,0,0,0.3);
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      grid-template-rows: repeat(2, 1fr);
      gap: 20px;
padding: 60px; /* espaço interno branco */
	width: fit-content;
      height: fit-content;
      overflow: hidden;
    }

    /* Cada box com proporção mais vertical, mas dentro do quadrado */
    .image-box {
      border-radius: 20px;
      background: #fff;
      display: flex;
      align-items: center;
      justify-content: center;
      overflow: hidden;
      position: relative;
      width: 440px;
      height: 575px;
      box-shadow: 0 5px 15px rgba(0,0,0,0.2);
    }

    .image-box img {
      width: 100%;
      height: 100%;
      object-fit: cover; /* cobre o retângulo sem distorcer */
      transition: transform 0.3s ease;
    }

    .image-box:hover img {
      transform: scale(1.03);
    }

    .watermark {
      position: absolute;
      bottom: 15px;
      right: 15px;
      background: rgba(255,255,255,0.9);
      padding: 8px 15px;
      border-radius: 20px;
      font-size: 14px;
      color: #146ab7;
      font-weight: bold;
    }

    .image-box:nth-child(1) { border: 3px solid #146ab7; }
    .image-box:nth-child(2) { border: 3px solid #0d47a1; }
    .image-box:nth-child(3) { border: 3px solid #1976d2; }
    .image-box:nth-child(4) { border: 3px solid #42a5f5; }
  </style>
</head>
<body>
  <div class="mosaic-container">
    <div class="image-box">
      <img src="{{ $json.imagem_url }}" alt="Imagem 1 da notícia">
      <div class="watermark">1</div>
    </div>
    <div class="image-box">
      <img src="{{ $json.imagem_url2 }}" alt="Imagem 2 da notícia">
      <div class="watermark">2</div>
    </div>
    <div class="image-box">
      <img src="{{ $json.imagem_url3 }}" alt="Imagem 3 da notícia">
      <div class="watermark">3</div>
    </div>
    <div class="image-box">
      <img src="https://raw.githubusercontent.com/getmia/miabuilder-images/main/RadarCorretor_Final_Post_Fixo.jpg" alt="Imagem 4 da notícia">
      <div class="watermark">4</div>
    </div>
  </div>
</body>
</html>

